6	//! Future type that bridges CUDA stream callbacks with Rust's async executor.
7	//!
8	//! [`DeviceFuture`] wraps a [`DeviceOperation`] and drives it through a
9	//! three-state machine:
10	//!
11	//! ```text
12	//!   Idle ──poll()──> Executing ──callback fires──> Complete
13	//!                       │                              │
14	//!                  (enqueue work                  (return result)
15	//!                   + host callback)
16	//! ```
17	//!
18	//! On the first poll the operation is executed on its assigned stream and a
19	//! host callback is registered via `cuLaunchHostFunc`. When the GPU reaches
20	//! the callback, it wakes the future through an [`AtomicWaker`], avoiding
21	//! busy-waits.
22	//!
23	//! [`DeviceOperation`]: crate::device_operation::DeviceOperation
24	//! [`AtomicWaker`]: futures::task::AtomicWaker
25	
26	use crate::device_operation::{DeviceOperation, ExecutionContext};
27	use crate::error::DeviceError;
28	use crate::reclaim;
29	use futures::task::AtomicWaker;
30	use std::future::Future;
31	use std::io::{self, Write};
32	use std::mem;
33	use std::pin::Pin;
34	use std::sync::Arc;
35	use std::sync::atomic::{AtomicBool, Ordering};
36	use std::task::{Context, Poll};
37	
38	/// Lifecycle state of a [`DeviceFuture`].
39	#[derive(Debug, Default, Eq, PartialEq, Copy, Clone)]
40	pub enum DeviceFutureState {
41	    /// The future was constructed in a failed state (e.g. scheduling error).
42	    Failed,
43	    /// Initial state: the operation has not yet been submitted to the GPU.
44	    #[default]
45	    Idle,
46	    /// The operation has been submitted; waiting for the stream callback.
47	    Executing,
48	    /// The result has been produced. Polling again will panic.
49	    Complete,
50	}
51	
52	/// Shared state between a [`DeviceFuture`] and its `cuLaunchHostFunc` callback.
53	///
54	/// The callback sets `complete` and wakes the stored waker, allowing the
55	/// executor to re-poll the future without busy-waiting.
56	#[derive(Debug, Default)]
57	pub struct StreamCallbackState {
58	    /// Waker registered by the executor during [`Future::poll`].
59	    pub(crate) waker: AtomicWaker,
60	    /// Set to `true` by the host callback when the GPU reaches the callback
61	    /// point in the stream.
62	    pub(crate) complete: AtomicBool,
63	}
64	
65	impl StreamCallbackState {
66	    /// Creates a new callback state with no registered waker and
67	    /// `complete = false`.
68	    pub fn new() -> Self {
69	        Self::default()
70	    }
71	
72	    /// Marks the stream callback as complete and wakes the associated future.
73	    ///
74	    /// Called from the `cuLaunchHostFunc` host-side callback.
75	    pub fn signal(&self) {
76	        self.complete.store(true, Ordering::Relaxed);
77	        self.waker.wake();
78	    }
79	}
80	
81	/// A [`Future`] that executes a [`DeviceOperation`] on a CUDA stream and
82	/// resolves when the GPU signals completion via a host callback.
83	///
84	/// Constructed by [`SchedulingPolicy::schedule`] or by the [`IntoFuture`] impl
85	/// on any `DeviceOperation`.
86	///
87	/// # Cancellation
88	///
89	/// Dropping the future never cancels submitted GPU work; kernels always run
90	/// to completion. Dropping an in-flight future records a CUDA event on the
91	/// assigned stream and parks the stored result in the [`reclaim`] limbo,
92	/// deferring host-side reclamation until the device timeline passes that
93	/// event. The drop itself never blocks on GPU progress.
94	///
95	/// [`reclaim`]: crate::reclaim
96	///
97	/// [`SchedulingPolicy::schedule`]: crate::scheduling_policies::SchedulingPolicy::schedule
98	/// [`IntoFuture`]: std::future::IntoFuture
99	#[derive(Debug)]
100	pub struct DeviceFuture<T: Send + 'static, DO: DeviceOperation<Output = T>> {
101	    /// The operation to execute. Consumed on first poll.
102	    pub(crate) device_operation: Option<DO>,
103	    /// Stream and context for execution. Set by the scheduling policy.
104	    pub(crate) execution_context: Option<ExecutionContext>,
105	    /// Holds the result between execution and final poll resolution.
106	    pub(crate) result: Option<T>,
107	    /// Holds an error when the future is in the `Failed` state.
108	    pub(crate) error: Option<DeviceError>,
109	    /// Current lifecycle state.
110	    pub(crate) state: DeviceFutureState,
111	    /// Shared state with the `cuLaunchHostFunc` callback.
112	    pub(crate) callback_state: Option<Arc<StreamCallbackState>>,
113	}
114	
115	impl<T: Send + 'static, DO: DeviceOperation<Output = T>> DeviceFuture<T, DO> {
116	    /// Creates an idle future with no operation or context attached.
117	    pub fn new() -> Self {
118	        Self::default()
119	    }
120	
121	    /// Creates a future that will immediately yield `Err(error)` on first poll.
122	    pub fn failed(error: DeviceError) -> Self {
123	        Self {
124	            execution_context: None,
125	            device_operation: None,
126	            state: DeviceFutureState::Failed,
127	            callback_state: None,
128	            result: None,
129	            error: Some(error),
130	        }
131	    }
132	
133	    /// Registers a `cuLaunchHostFunc` callback that will signal `waker_state`
134	    /// when the GPU reaches this point in the stream.
135	    ///
136	    /// # Safety
137	    ///
138	    /// The execution context must hold a valid, non-destroyed CUDA stream.
139	    unsafe fn register_callback(
140	        &self,
141	        waker_state: Arc<StreamCallbackState>,
142	    ) -> Result<(), DeviceError> {
143	        let ctx = self.execution_context.as_ref().ok_or_else(|| {
144	            DeviceError::Internal("Cannot execute future without an execution context.".to_string())
145	        })?;
146	        ctx.get_cuda_stream().launch_host_function(move || {
147	            waker_state.signal();
148	        })?;
149	        Ok(())
150	    }
151	
152	    /// Takes the stored operation, executes it on the bound stream, and stashes
153	    /// the result. Called exactly once during the `Idle -> Executing` transition.
154	    fn execute(&mut self) -> Result<(), DeviceError> {
155	        let ctx = self.execution_context.as_ref().ok_or_else(|| {
156	            DeviceError::Internal("Cannot execute future without an execution context.".to_string())
157	        })?;
158	        let operation = self
159	            .device_operation
160	            .take()
161	            .ok_or_else(|| DeviceError::Internal("No operation has been set.".to_string()))?;
162	        let out = unsafe { operation.execute(ctx) }?;
163	        self.result = Some(out);
164	        Ok(())
165	    }
166	
167	    /// Returns `true` when GPU work was submitted but the stored result has
168	    /// not been handed to the caller.
169	    ///
170	    /// `result` is only populated by a successful [`execute`], so a stored
171	    /// result implies submitted GPU work. The state check excludes futures
172	    /// that never submitted anything (`Idle`, `Failed`); a `Complete` future
173	    /// can still hold a result when callback registration failed after a
174	    /// successful launch.
175	    ///
176	    /// [`execute`]: Self::execute
177	    fn has_undelivered_submission(&self) -> bool {
178	        matches!(
179	            self.state,
180	            DeviceFutureState::Executing | DeviceFutureState::Complete
181	        ) && self.result.is_some()
182	    }
183	
184	    /// Hands a submitted-but-undelivered result to deferred reclamation.
185	    ///
186	    /// Records a completion event on the assigned stream and parks the
187	    /// result in the [`reclaim`] limbo; the result is dropped by a later
188	    /// sweep once the device timeline passes the event. Never blocks in
189	    /// this path. Only when the event cannot be recorded does it fall back
190	    /// to [`cleanup_executing_result_with`], which synchronizes the stream
191	    /// and, if even that fails, leaks the result loudly.
192	    ///
193	    /// [`cleanup_executing_result_with`]: Self::cleanup_executing_result_with
194	    fn reclaim_in_flight_result(&mut self) {
195	        if !self.has_undelivered_submission() {
196	            return;
197	        }
198	        let stream = self
199	            .execution_context
200	            .as_ref()
201	            .map(|ctx| Arc::clone(ctx.get_cuda_stream()));
202	        if let Some(stream) = &stream
203	            && let Ok(event) = stream.record_event(None)
204	        {
205	            let result = self.result.take().expect("Checked above.");
206	            reclaim::park(event, Box::new(result));
207	            return;
208	        }
209	        // No execution context, or the driver rejected the event record.
210	        // Fall back to the blocking path before resorting to a loud leak.
211	        self.cleanup_executing_result_with(move || {
212	            let stream = stream.ok_or_else(|| {
213	                DeviceError::Internal(
214	                    "Cannot clean up an in-flight future without an execution context.".to_string(),
215	                )
216	            })?;
217	            stream.synchronize().map_err(DeviceError::Driver)
218	        });
219	    }
220	
221	    /// Blocking cleanup fallback: runs `synchronize` and drops the stored
222	    /// result on success; on failure the result is leaked loudly, because
223	    /// dropping resources the device may still use is worse than leaking.
224	    ///
225	    /// Deferred (non-blocking) reclamation in
226	    /// [`reclaim_in_flight_result`](Self::reclaim_in_flight_result) is
227	    /// always preferred; this path only runs when no completion event could
228	    /// be recorded.
229	    fn cleanup_executing_result_with<F>(&mut self, synchronize: F)
230	    where
231	        F: FnOnce() -> Result<(), DeviceError>,
232	    {
233	        if !self.has_undelivered_submission() {
234	            return;
235	        }
236	
237	        let Some(result) = self.result.take() else {
238	            return;
239	        };
240	
241	        if let Err(error) = synchronize() {
242	            let mut stderr = io::stderr().lock();
243	            let _ = writeln!(
244	                stderr,
245	                "cuda-async: leaking in-flight future result after cleanup failure: {}",
246	                error
247	            );
248	            // If cleanup cannot prove the stream is idle, leaking the owned
249	            // result is safer than dropping buffers that device work may still
250	            // be using.
251	            mem::forget(result);
252	            return;
253	        }
254	
255	        drop(result);
256	    }
257	}
258	
259	impl<T: Send + 'static, DO: DeviceOperation<Output = T>> Default for DeviceFuture<T, DO> {
260	    fn default() -> Self {
261	        Self {
262	            device_operation: Default::default(),
263	            execution_context: Default::default(),
264	            result: Default::default(),
265	            error: Default::default(),
266	            state: Default::default(),
267	            callback_state: Default::default(),
268	        }
269	    }
270	}
271	
272	/// `DeviceFuture` does not contain self-referential pointers, so it is safe
273	/// to move.
274	impl<T: Send + 'static, DO: DeviceOperation<Output = T>> Unpin for DeviceFuture<T, DO> {}
275	
276	impl<T: Send + 'static, DO: DeviceOperation<Output = T>> Drop for DeviceFuture<T, DO> {
277	    fn drop(&mut self) {
278	        // Reclaim earlier cancellations whose GPU work has since finished,
279	        // then defer this future's own in-flight result (if any).
280	        reclaim::sweep();
281	        self.reclaim_in_flight_result();
282	    }
283	}
284	
285	/// State-machine implementation of [`Future`] for CUDA device work.
286	///
287	/// | State       | Action on poll                                          |
288	/// |-------------|---------------------------------------------------------|
289	/// | `Failed`    | Immediately returns `Err`.                              |
290	/// | `Idle`      | Executes the operation, registers callback, -> Pending. |
291	/// | `Executing` | Checks callback flag; returns result if done.           |
292	/// | `Complete`  | Panics -- must not poll after completion.               |
293	impl<T: Send + 'static, DO: DeviceOperation<Output = T>> Future for DeviceFuture<T, DO> {
294	    type Output = Result<T, DeviceError>;
295	    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
296	        // Opportunistically reclaim cancelled results whose GPU work has
297	        // completed. Cheap when nothing is parked (one atomic load).
298	        reclaim::sweep();
299	
300	        if self.state == DeviceFutureState::Failed {
301	            self.state = DeviceFutureState::Complete;
302	            let error = self
303	                .error
304	                .take()
305	                .expect("Failed state must carry an error.");
306	            return Poll::Ready(Err(error));
307	        }
308	
309	        if self.callback_state.is_none() {
310	            self.callback_state = Some(Arc::new(StreamCallbackState::new()));
311	        }
312	        let waker_state = self
313	            .callback_state
314	            .as_ref()
315	            .map(Arc::clone)
316	            .expect("Impossible.");
317	
318	        match self.state {
319	            DeviceFutureState::Idle => {
320	                waker_state.waker.register(cx.waker());
321	                if let Err(e) = self.execute() {
322	                    self.state = DeviceFutureState::Complete;
323	                    return Poll::Ready(Err(e));
324	                }
325	                if let Err(e) = unsafe { self.register_callback(Arc::clone(&waker_state)) } {
326	                    self.state = DeviceFutureState::Complete;
327	                    // The launch already succeeded, so GPU work is in flight
328	                    // and `result` holds the owned resources. Route them
329	                    // through deferred reclamation instead of leaving them
330	                    // for an immediate drop while the kernel may still run
331	                    // (issue #99, callback-registration-failure path).
332	                    self.reclaim_in_flight_result();
333	                    return Poll::Ready(Err(e));
334	                }
335	                self.state = DeviceFutureState::Executing;
336	                Poll::Pending
337	            }
338	            DeviceFutureState::Executing => {
339	                if waker_state.complete.load(Ordering::Relaxed) {
340	                    self.state = DeviceFutureState::Complete;
341	                    return Poll::Ready(Ok(self.result.take().expect("Expected result.")));
342	                }
343	                waker_state.waker.register(cx.waker());
344	                if waker_state.complete.load(Ordering::Relaxed) {
345	                    self.state = DeviceFutureState::Complete;
346	                    Poll::Ready(Ok(self.result.take().expect("Expected result.")))
347	                } else {
348	                    Poll::Pending
349	                }
350	            }
351	            DeviceFutureState::Complete => panic!("Poll called after completion."),
352	            DeviceFutureState::Failed => unreachable!(),
353	        }
354	    }
355	}
356	
357	#[cfg(test)]
358	mod tests {
359	    use super::*;
360	    use crate::device_operation::Value;
361	    use std::sync::Arc;
362	    use std::sync::Mutex;
363	    use std::sync::atomic::{AtomicUsize, Ordering};
364	
365	    #[derive(Clone)]
366	    struct DropTracker {
367	        events: Arc<Mutex<Vec<&'static str>>>,
368	    }
369	
370	    impl Drop for DropTracker {
371	        fn drop(&mut self) {
372	            self.events.lock().unwrap().push("drop");
373	        }
374	    }
375	
376	    #[test]
377	    fn cleanup_executing_result_synchronizes_before_drop() {
378	        let events = Arc::new(Mutex::new(Vec::new()));
379	        let tracker = DropTracker {
380	            events: Arc::clone(&events),
381	        };
382	        let mut future: DeviceFuture<DropTracker, Value<DropTracker>> = DeviceFuture {
383	            device_operation: None,
384	            execution_context: None,
385	            result: Some(tracker),
386	            error: None,
387	            state: DeviceFutureState::Executing,
388	            callback_state: None,
389	        };
390	
391	        future.cleanup_executing_result_with(|| {
392	            events.lock().unwrap().push("sync");
393	            Ok(())
394	        });
395	
396	        assert_eq!(events.lock().unwrap().as_slice(), ["sync", "drop"]);
397	        assert!(future.result.is_none());
398	    }
399	
400	    #[test]
401	    fn cleanup_executing_result_leaks_when_synchronize_fails() {
402	        let drops = Arc::new(AtomicUsize::new(0));
403	
404	        struct CountDrop(Arc<AtomicUsize>);
405	
406	        impl Drop for CountDrop {
407	            fn drop(&mut self) {
408	                self.0.fetch_add(1, Ordering::Relaxed);
409	            }
410	        }
411	
412	        let mut future: DeviceFuture<CountDrop, Value<CountDrop>> = DeviceFuture {
413	            device_operation: None,
414	            execution_context: None,
415	            result: Some(CountDrop(Arc::clone(&drops))),
416	            error: None,
417	            state: DeviceFutureState::Executing,
418	            callback_state: None,
419	        };
420	
421	        future.cleanup_executing_result_with(|| Err(DeviceError::Internal("boom".to_string())));
422	
423	        assert_eq!(drops.load(Ordering::Relaxed), 0);
424	        assert!(future.result.is_none());
425	    }
426	
427	    /// The shape left behind by issue #99's second path: `execute()`
428	    /// succeeded (GPU work submitted, `result` populated) but
429	    /// `register_callback()` failed, so poll flipped the state to
430	    /// `Complete` with the result still stored. Cleanup must treat that
431	    /// exactly like a cancelled `Executing` future.
432	    #[test]
433	    fn cleanup_covers_complete_future_left_by_callback_registration_failure() {
434	        let events = Arc::new(Mutex::new(Vec::new()));
435	        let tracker = DropTracker {
436	            events: Arc::clone(&events),
437	        };
438	        let mut future: DeviceFuture<DropTracker, Value<DropTracker>> = DeviceFuture {
439	            device_operation: None,
440	            execution_context: None,
441	            result: Some(tracker),
442	            error: None,
443	            state: DeviceFutureState::Complete,
444	            callback_state: None,
445	        };
446	
447	        assert!(future.has_undelivered_submission());
448	        future.cleanup_executing_result_with(|| {
449	            events.lock().unwrap().push("sync");
450	            Ok(())
451	        });
452	
453	        assert_eq!(events.lock().unwrap().as_slice(), ["sync", "drop"]);
454	        assert!(future.result.is_none());
455	        assert!(!future.has_undelivered_submission());
456	    }
457	
458	    /// A `Complete` future whose result was already delivered to the caller
459	    /// has nothing to reclaim.
460	    #[test]
461	    fn cleanup_is_noop_after_result_delivery() {
462	        let mut future: DeviceFuture<u32, Value<u32>> = DeviceFuture {
463	            device_operation: None,
464	            execution_context: None,
465	            result: None,
466	            error: None,
467	            state: DeviceFutureState::Complete,
468	            callback_state: None,
469	        };
470	
471	        assert!(!future.has_undelivered_submission());
472	        future.cleanup_executing_result_with(|| {
473	            panic!("delivered futures must not synchronize during cleanup")
474	        });
475	        future.reclaim_in_flight_result();
476	    }
477	
478	    #[test]
479	    fn cleanup_is_noop_for_idle_future() {
480	        let drops = Arc::new(AtomicUsize::new(0));
481	
482	        struct CountDrop(Arc<AtomicUsize>);
483	
484	        impl Drop for CountDrop {
485	            fn drop(&mut self) {
486	                self.0.fetch_add(1, Ordering::Relaxed);
487	            }
488	        }
489	
490	        let mut future: DeviceFuture<CountDrop, Value<CountDrop>> = DeviceFuture {
491	            device_operation: None,
492	            execution_context: None,
493	            result: Some(CountDrop(Arc::clone(&drops))),
494	            error: None,
495	            state: DeviceFutureState::Idle,
496	            callback_state: None,
497	        };
498	
499	        future.cleanup_executing_result_with(|| {
500	            panic!("idle futures should not synchronize during cleanup")
501	        });
502	
503	        assert_eq!(drops.load(Ordering::Relaxed), 0);
504	        assert!(future.result.is_some());
505	
506	        drop(future);
507	        assert_eq!(drops.load(Ordering::Relaxed), 1);
508	    }
509	}
