301	/// Sequential composition: execute `DI`, then pass its output through `F` to
302	/// produce a second operation `DO`, and execute that.
303	///
304	/// Produced by [`DeviceOperation::and_then`].
305	pub struct AndThen<I: Send, DI, O: Send, DO, F>
306	where
307	    DI: DeviceOperation<Output = I>,
308	    DO: DeviceOperation<Output = O>,
309	    F: FnOnce(I) -> DO,
310	{
