715	/// Shared state backing the [`SelectLeft`] / [`SelectRight`] split.
716	///
717	/// Holds the source operation and its memoized results. The first selector
718	/// to execute triggers the source; subsequent selectors read the cached
719	/// values. Interior mutability is used via [`UnsafeCell`] because execution
720	/// is always sequential within a single stream.
721	pub struct Select<T1: Send, T2: Send, DI: DeviceOperation<Output = (T1, T2)>> {
722	    /// Guards one-shot execution of the source operation.
723	    computed: AtomicBool,
724	    /// Source operation. Consumed on the first call to [`execute`](Self::execute).
725	    input: UnsafeCell<Option<DI>>,
726	    /// Cached left result.
727	    left: UnsafeCell<Option<T1>>,
728	    /// Cached right result.
729	    right: UnsafeCell<Option<T2>>,
730	}
731	
732	impl<T1: Send, T2: Send, DI: DeviceOperation<Output = (T1, T2)>> Select<T1, T2, DI> {
733	    /// Executes the source operation if it has not been executed yet, caching
734	    /// both halves of the tuple.
735	    ///
736	    /// # Safety
737	    ///
738	    /// Must only be called from within a single-stream execution context.
739	    /// Concurrent calls from different threads would race on the `UnsafeCell`s.
740	    unsafe fn execute(self: &Arc<Self>, context: &ExecutionContext) -> Result<(), DeviceError> {
741	        unsafe {
742	            if !self.computed.load(Ordering::Acquire) {
743	                let input = self.input.get();
744	                let input = input.as_mut();
745	                let input = input.unwrap().take().ok_or_else(|| {
746	                    crate::error::device_error(context.get_device_id(), "Select operation failed.")
747	                })?;
748	                let (left, right) = input.execute(context)?;
749	                *self.left.get() = Some(left);
750	                *self.right.get() = Some(right);
751	                self.computed.store(true, Ordering::Release);
752	            }
753	            Ok(())
754	        }
755	    }
756	
757	    /// Takes the cached left value. Must be called after [`execute`](Self::execute).
758	    ///
759	    /// # Safety
760	    ///
761	    /// Caller must ensure `execute` has completed and this is called at most once.
762	    unsafe fn left(&self) -> T1 {
763	        let cell = self.left.get();
764	        let cell = unsafe { cell.as_mut() };
765	        cell.unwrap().take().unwrap()
766	    }
767	
768	    /// Takes the cached right value. Must be called after [`execute`](Self::execute).
769	    ///
770	    /// # Safety
771	    ///
772	    /// Caller must ensure `execute` has completed and this is called at most once.
773	    unsafe fn right(&self) -> T2 {
774	        let cell = self.right.get();
775	        let cell = unsafe { cell.as_mut() };
776	        cell.unwrap().take().unwrap()
777	    }
778	}
