7	//!
8	//! [`AsyncKernelLaunch`] accumulates a kernel function reference, launch
9	//! configuration, and type-erased argument pointers, then submits the launch
10	//! through the CUDA driver when executed as a [`DeviceOperation`].
11	//!
12	//! Arguments are heap-allocated via [`KernelArgument::push_arg`] and freed when
13	//! the launcher is dropped after submission. This keeps the pointed-to values
14	//! alive until `cuLaunchKernel` / `cuLaunchKernelEx` has copied the launch
15	//! parameter values out of the host-side argument array.
16	//!
17	//! [`DeviceOperation`]: crate::device_operation::DeviceOperation
18	
19	use crate::device_context::with_default_device_policy;
20	use crate::device_future::DeviceFuture;
21	use crate::device_operation::{DeviceOperation, ExecutionContext};
22	use crate::error::DeviceError;
23	use crate::scheduling_policies::SchedulingPolicy;
24	use cuda_core::{CudaFunction, CudaStream, LaunchConfig};
25	use std::ffi::c_void;
26	use std::future::IntoFuture;
27	use std::marker::PhantomData;
28	use std::sync::Arc;
29	
30	/// Builder that accumulates kernel arguments and submits a CUDA kernel launch.
31	///
32	/// Implements [`DeviceOperation`] so it can be composed with other operations
33	/// and scheduled onto any stream. Also implements [`IntoFuture`] for `.await`
34	/// syntax.
35	#[derive(Debug)]
36	pub struct AsyncKernelLaunch<'a> {
37	    /// Handle to the compiled device function.
38	    pub func: Arc<CudaFunction>,
39	    /// Heap-allocated, type-erased argument storage passed to the CUDA driver.
40	    args: KernelArgStorage,
41	    /// Grid/block dimensions and shared memory size. Must be set before launch.
42	    cfg: Option<LaunchConfig>,
43	    /// Optional thread-block cluster dimensions for `cuLaunchKernelEx`.
44	    cluster_dim: Option<(u32, u32, u32)>,
45	    /// When `true`, launch via `cuLaunchKernelEx` with
46	    /// `CU_LAUNCH_ATTRIBUTE_COOPERATIVE` set, which guarantees the whole grid
47	    /// is co-resident on the device (required for `cuda_device::grid::sync()`).
48	    cooperative: bool,
49	    /// Ties borrowed device buffers to the lazy launch operation.
50	    _borrows: PhantomData<&'a mut ()>,
51	}
52	
53	/// # Safety
54	///
55	/// The `*mut c_void` pointers in `args` are heap-allocated boxes that do not
56	/// alias mutable state. The `Arc<CudaFunction>` is `Send + Sync`.
57	unsafe impl<'a> Send for AsyncKernelLaunch<'a> {}
58	
59	#[derive(Debug, Default)]
60	struct KernelArgStorage {
61	    ptrs: Vec<*mut c_void>,
62	    drops: Vec<unsafe fn(*mut c_void)>,
63	}
64	
65	impl Drop for KernelArgStorage {
66	    fn drop(&mut self) {
67	        for (arg, drop_arg) in self.ptrs.drain(..).zip(self.drops.drain(..)) {
68	            unsafe { drop_arg(arg) };
69	        }
70	    }
71	}
72	
73	impl KernelArgStorage {
74	    fn push_boxed_arg<T>(&mut self, arg: Box<T>) {
75	        unsafe fn drop_box<T>(arg: *mut c_void) {
76	            let _ = unsafe { Box::from_raw(arg as *mut T) };
77	        }
78	
79	        self.ptrs.push(Box::into_raw(arg) as *mut c_void);
80	        self.drops.push(drop_box::<T>);
81	    }
82	
83	    fn push_scalar_arg<T: Copy>(&mut self, arg: T) {
84	        self.push_boxed_arg(Box::new(arg));
85	    }
86	
87	    fn as_mut_slice(&mut self) -> &mut [*mut c_void] {
88	        &mut self.ptrs
89	    }
90	}
91	
92	impl<'a> AsyncKernelLaunch<'a> {
93	    /// Creates a launcher for `func` with no arguments and no launch config.
94	    pub fn new(func: Arc<CudaFunction>) -> Self {
95	        Self {
96	            func,
97	            args: KernelArgStorage::default(),
98	            cfg: None,
99	            cluster_dim: None,
100	            cooperative: false,
101	            _borrows: PhantomData,
102	        }
103	    }
104	
105	    /// Appends a by-value `Copy` argument to the kernel launch packet.
106	    ///
107	    /// This is the typed-module path used for scalar, raw-pointer, custom
108	    /// `Copy` structs, and `Copy` closure arguments.
109	    #[inline(always)]
110	    pub fn push_scalar_arg<T: Copy + 'a>(&mut self, arg: T) -> &mut Self {
111	        self.args.push_scalar_arg(arg);
112	        self
113	    }
114	
115	    /// Appends a kernel argument. The value is heap-allocated and its pointer
116	    /// stored for the driver call.
117	    ///
118	    /// Scalars like `u32`, `f32`, `u64` etc. are auto-boxed -- no need to
119	    /// wrap them in `Box::new`.
120	    ///
121	    /// The allocated storage remains alive until launch submission finishes or
122	    /// the builder is dropped without launching.
123	    #[inline(always)]
124	    pub fn push_arg<T: KernelArgument>(&mut self, arg: T) -> &mut Self {
125	        arg.push_arg(self);
126	        self
127	    }
128	
129	    /// Appends multiple kernel arguments at once from a tuple.
130	    ///
131	    /// Equivalent to chained [`push_arg`](Self::push_arg) calls but allows
132	    /// grouping all arguments in a single expression:
133	    ///
134	    /// ```ignore
135	    /// launch.push_args((m, n, k, alpha, a_ptr, a_len, b_ptr, b_len, beta, c_ptr, c_len));
136	    /// ```
137	    ///
138	    /// Supports tuples up to 32 elements.
139	    #[inline(always)]
140	    pub fn push_args<T: KernelArguments>(&mut self, args: T) -> &mut Self {
141	        args.push_args(self);
142	        self
143	    }
144	
145	    /// Sets the grid/block dimensions and shared memory size for the launch.
146	    pub fn set_launch_config(&mut self, cfg: LaunchConfig) -> &mut Self {
147	        self.cfg = Some(cfg);
148	        self
149	    }
150	
151	    /// Sets thread-block cluster dimensions for a cluster launch.
152	    pub fn set_cluster_dim(&mut self, cluster_dim: (u32, u32, u32)) -> &mut Self {
153	        self.cluster_dim = Some(cluster_dim);
154	        self
155	    }
156	
157	    /// Marks this launch as cooperative (`CU_LAUNCH_ATTRIBUTE_COOPERATIVE`).
158	    ///
159	    /// A cooperative launch guarantees every block in the grid is co-resident
160	    /// on the device, which is the precondition for grid-wide barriers like
161	    /// `cuda_device::grid::sync()`. May be combined with
162	    /// [`set_cluster_dim`](Self::set_cluster_dim); both attributes are then
163	    /// passed to `cuLaunchKernelEx` in the same call.
164	    pub fn set_cooperative(&mut self, cooperative: bool) -> &mut Self {
165	        self.cooperative = cooperative;
166	        self
167	    }
168	
169	    /// Submits the kernel to `stream` via `cuLaunchKernel`, or via
170	    /// `cuLaunchKernelEx` when cluster dimensions or a cooperative launch
171	    /// were requested.
172	    ///
173	    /// # Safety
174	    ///
175	    /// - `self.func` must refer to a kernel loaded from the same CUDA context
176	    ///   that owns `stream`.
177	    /// - All argument pointers in `self.args` must point to correctly typed and
178	    ///   aligned host-side values for the kernel's formal parameters.
179	    /// - The pointed-to argument values must remain valid until launch
180	    ///   submission returns. The stream-aware launch helper binds the correct
181	    ///   context before calling into the CUDA driver.
182	    ///
183	    /// # Errors
184	    ///
185	    /// Returns [`DeviceError::Launch`] if no launch config was set, or
186	    /// [`DeviceError::Driver`] if context binding or launch submission fails.
187	    unsafe fn launch(mut self, stream: &Arc<CudaStream>) -> Result<(), DeviceError> {
188	        let cfg = self
189	            .cfg
190	            .ok_or_else(|| DeviceError::Launch("Launch config not set.".to_string()))?;
191	        let result = match (self.cluster_dim, self.cooperative) {
192	            (Some(cluster_dim), true) => unsafe {
193	                cuda_core::launch_kernel_ex_cooperative_on_stream(
194	                    self.func.as_ref(),
195	                    cfg.grid_dim,
196	                    cfg.block_dim,
197	                    cfg.shared_mem_bytes,
198	                    cluster_dim,
199	                    stream.as_ref(),
200	                    self.args.as_mut_slice(),
201	                )
202	            },
203	            (Some(cluster_dim), false) => unsafe {
204	                cuda_core::launch_kernel_ex_on_stream(
205	                    self.func.as_ref(),
206	                    cfg.grid_dim,
207	                    cfg.block_dim,
208	                    cfg.shared_mem_bytes,
209	                    cluster_dim,
210	                    stream.as_ref(),
211	                    self.args.as_mut_slice(),
212	                )
213	            },
214	            (None, true) => unsafe {
215	                cuda_core::launch_kernel_cooperative_on_stream(
216	                    self.func.as_ref(),
217	                    cfg.grid_dim,
218	                    cfg.block_dim,
219	                    cfg.shared_mem_bytes,
220	                    stream.as_ref(),
221	                    self.args.as_mut_slice(),
222	                )
223	            },
224	            (None, false) => unsafe {
225	                cuda_core::launch_kernel_on_stream(
226	                    self.func.as_ref(),
227	                    cfg.grid_dim,
228	                    cfg.block_dim,
229	                    cfg.shared_mem_bytes,
230	                    stream.as_ref(),
231	                    self.args.as_mut_slice(),
232	                )
233	            },
234	        };
235	        result.map_err(DeviceError::Driver)?;
236	        Ok(())
237	    }
238	}
239	
240	/// Owns resources for a lazy async kernel launch and returns them when the GPU
241	/// work has completed.
242	#[derive(Debug)]
243	pub struct OwnedAsyncKernelLaunch<R: Send> {
244	    launch: AsyncKernelLaunch<'static>,
245	    resources: R,
246	}
247	
248	unsafe impl<R: Send> Send for OwnedAsyncKernelLaunch<R> {}
249	
250	impl<R: Send> OwnedAsyncKernelLaunch<R> {
251	    /// Creates an owned async kernel operation from a prepared launch and the
252	    /// resources that must stay alive until completion.
253	    pub fn new(launch: AsyncKernelLaunch<'static>, resources: R) -> Self {
254	        Self { launch, resources }
255	    }
256	}
257	
258	/// Trait for types that can be marshalled into a CUDA kernel argument list.
259	///
260	/// Implementors heap-allocate the value and push a `*mut c_void` into the
261	/// launcher's argument vector.
262	///
263	/// Implemented for all common scalar primitives (`u8`–`u64`, `i8`–`i64`,
264	/// `f32`, `f64`, `usize`, `isize`, `bool`) so callers can write
265	/// `.push_arg(42u32)` without manual `Box::new`.
266	pub trait KernelArgument {
267	    /// Heap-allocates `self` and appends the pointer to `launcher.args`.
268	    fn push_arg(self, launcher: &mut AsyncKernelLaunch<'_>);
269	}
270	
271	/// Passes the box's raw pointer directly as a kernel argument.
272	///
273	/// This is the low-level escape hatch. Prefer passing scalars directly -- they
274	/// are auto-boxed via the blanket scalar impls.
275	impl<T: 'static> KernelArgument for Box<T> {
276	    fn push_arg(self, launcher: &mut AsyncKernelLaunch<'_>) {
277	        launcher.args.push_boxed_arg(self);
278	    }
279	}
280	
281	macro_rules! impl_scalar_kernel_arg {
282	    ($($t:ty),*) => {
283	        $(
284	            impl KernelArgument for $t {
285	                #[inline(always)]
286	                fn push_arg(self, launcher: &mut AsyncKernelLaunch<'_>) {
287	                    launcher.push_scalar_arg(self);
288	                }
289	            }
290	        )*
291	    };
292	}
293	
294	impl_scalar_kernel_arg!(
295	    u8, u16, u32, u64, usize, i8, i16, i32, i64, isize, f32, f64, bool
296	);
297	
298	// ---------------------------------------------------------------------------
299	// KernelArguments — push multiple heterogeneous args in a single call
300	// ---------------------------------------------------------------------------
301	
302	/// Trait for a group of kernel arguments that can be pushed together.
303	///
304	/// Implemented for tuples of [`KernelArgument`] types up to arity 32, enabling
305	/// `launch.push_args((dim_m, dim_n, alpha, ptr, len))` as an alternative to
306	/// chained `.push_arg()` calls.
307	#[diagnostic::on_unimplemented(
308	    message = "cannot push `{Self}` as kernel arguments",
309	    note = "KernelArguments is implemented for tuples of KernelArgument types up to 32 elements"
310	)]
311	pub trait KernelArguments {
312	    /// Pushes every element into `launcher` in order.
313	    fn push_args(self, launcher: &mut AsyncKernelLaunch<'_>);
314	}
315	
316	macro_rules! impl_kernel_args_tuple {
317	    // Base case: empty tuple
318	    () => {
319	        impl KernelArguments for () {
320	            #[inline(always)]
321	            fn push_args(self, _launcher: &mut AsyncKernelLaunch<'_>) {}
322	        }
323	    };
324	    // Recursive case: (A, B, C, ...) where each element is a KernelArgument
325	    ($($idx:tt : $T:ident),+) => {
326	        impl<$($T: KernelArgument),+> KernelArguments for ($($T,)+) {
327	            #[inline(always)]
328	            fn push_args(self, launcher: &mut AsyncKernelLaunch<'_>) {
329	                $(launcher.push_arg(self.$idx);)+
330	            }
331	        }
332	    };
333	}
