368	
369	/// Launches the kernel on the stream bound to the execution context.
370	impl<'a> DeviceOperation for AsyncKernelLaunch<'a> {
371	    type Output = ();
372	
373	    unsafe fn execute(self, ctx: &ExecutionContext) -> Result<(), DeviceError> {
374	        unsafe { self.launch(ctx.get_cuda_stream()) }
375	    }
376	}
377	
378	/// Schedules the kernel launch via the thread-local default scheduling policy.
379	impl<'a> IntoFuture for AsyncKernelLaunch<'a> {
380	    type Output = Result<(), DeviceError>;
381	    type IntoFuture = DeviceFuture<(), AsyncKernelLaunch<'a>>;
382	    fn into_future(self) -> Self::IntoFuture {
383	        match with_default_device_policy(|policy| policy.schedule(self)) {
384	            Ok(Ok(future)) => future,
385	            Ok(Err(e)) | Err(e) => DeviceFuture::failed(e),
386	        }
387	    }
388	}
389	
390	impl<R: Send + 'static> DeviceOperation for OwnedAsyncKernelLaunch<R> {
391	    type Output = R;
392	
393	    unsafe fn execute(self, ctx: &ExecutionContext) -> Result<R, DeviceError> {
394	        let Self { launch, resources } = self;
395	        unsafe { launch.launch(ctx.get_cuda_stream()) }?;
396	        Ok(resources)
397	    }
398	}
399	
400	impl<R: Send + 'static> IntoFuture for OwnedAsyncKernelLaunch<R> {
401	    type Output = Result<R, DeviceError>;
402	    type IntoFuture = DeviceFuture<R, OwnedAsyncKernelLaunch<R>>;
403	
404	    fn into_future(self) -> Self::IntoFuture {
405	        match with_default_device_policy(|policy| policy.schedule(self)) {
406	            Ok(Ok(future)) => future,
407	            Ok(Err(e)) | Err(e) => DeviceFuture::failed(e),
408	        }
409	    }
410	}
