412	#[cfg(test)]
413	mod tests {
414	    use super::*;
415	    use std::cell::Cell;
416	    use std::rc::Rc;
417	
418	    #[repr(C)]
419	    #[derive(Clone, Copy, Debug, PartialEq)]
420	    struct TestParams {
421	        scale: f32,
422	        bias: i32,
423	    }
424	
425	    #[test]
426	    fn scalar_arg_storage_accepts_custom_copy_value() {
427	        let mut storage = KernelArgStorage::default();
428	        let params = TestParams {
429	            scale: 2.0,
430	            bias: 3,
431	        };
432	
433	        storage.push_scalar_arg(params);
434	
435	        assert_eq!(storage.ptrs.len(), 1);
436	        assert_eq!(unsafe { *(storage.ptrs[0] as *const TestParams) }, params);
437	    }
438	
439	    #[test]
440	    fn arg_storage_drops_values_with_their_original_type() {
441	        struct DropCounter(Rc<Cell<usize>>);
442	
443	        impl Drop for DropCounter {
444	            fn drop(&mut self) {
445	                self.0.set(self.0.get() + 1);
446	            }
447	        }
448	
449	        let drops = Rc::new(Cell::new(0));
450	        let mut storage = KernelArgStorage::default();
451	
452	        storage.push_boxed_arg(Box::new(DropCounter(Rc::clone(&drops))));
453	        assert_eq!(drops.get(), 0);
454	
455	        drop(storage);
456	        assert_eq!(drops.get(), 1);
457	    }
458	}
