103	        &self,
104	        op: O,
105	    ) -> Result<DeviceFuture<T, O>, DeviceError>;
106	
107	    /// Executes `op` synchronously on a policy-chosen stream and blocks until
108	    /// the stream is idle.
109	    fn sync<T: Send, O: DeviceOperation<Output = T>>(&self, op: O) -> Result<T, DeviceError>;
110	}
111	
112	/// Round-robin scheduler over a fixed-size pool of CUDA streams.
113	///
114	/// Each call to [`schedule`](SchedulingPolicy::schedule) or
115	/// [`sync`](SchedulingPolicy::sync) atomically advances the stream index,
116	/// distributing work across streams to enable hardware-level overlap of
117	/// independent kernels and memory transfers.
118	#[derive(Debug)]
119	pub struct StreamPoolRoundRobin {
120	    /// Device ordinal this pool belongs to.
121	    device_id: usize,
122	    /// Monotonically increasing counter; wrapped with `% num_streams`.
123	    next_stream_idx: AtomicUsize,
124	    /// Number of streams in the pool.
125	    pub(crate) num_streams: usize,
126	    /// `None` until [`init`](SchedulingPolicy::init) is called.
127	    pub(crate) stream_pool: Option<Vec<Arc<CudaStream>>>,
128	}
129	
130	impl StreamPoolRoundRobin {
131	    /// Creates an un-initialized round-robin policy for `device_id` with
132	    /// `num_streams` streams.
133	    ///
134	    /// # Safety
135	    ///
136	    /// The caller must call [`SchedulingPolicy::init`] before scheduling any
137	    /// operations. Using the policy before initialization produces an error.
138	    pub unsafe fn new(device_id: usize, num_streams: usize) -> Self {
139	        Self {
140	            device_id,
141	            num_streams,
142	            stream_pool: None,
143	            next_stream_idx: AtomicUsize::new(0),
144	        }
145	    }
146	}
147	
148	impl SchedulingPolicy for StreamPoolRoundRobin {
149	    /// Allocates `num_streams` CUDA streams on the provided context.
150	    fn init(&mut self, ctx: &Arc<CudaContext>) -> Result<(), DeviceError> {
151	        let mut pool = vec![];
152	        for _ in 0..self.num_streams {
153	            pool.push(ctx.new_stream()?);
154	        }
155	        self.stream_pool = Some(pool);
156	        Ok(())
157	    }
158	
159	    /// Picks the next stream (round-robin), executes `op`, and synchronizes.
160	    fn sync<T: Send, O: DeviceOperation<Output = T>>(&self, op: O) -> Result<T, DeviceError> {
161	        let idx = self
162	            .next_stream_idx
163	            .fetch_add(1, std::sync::atomic::Ordering::Relaxed)
164	            % self.num_streams;
165	        let pool = self
166	            .stream_pool
167	            .as_ref()
168	            .ok_or_else(|| device_error(self.device_id, "Stream pool not initialized."))?;
169	        op.sync_on(&pool[idx])
170	    }
171	
172	    /// Picks the next stream (round-robin) and wraps `op` in a
173	    /// [`DeviceFuture`].
174	    fn schedule<T: Send, O: DeviceOperation<Output = T>>(
175	        &self,
176	        op: O,
177	    ) -> Result<DeviceFuture<T, O>, DeviceError> {
178	        let idx = self
179	            .next_stream_idx
180	            .fetch_add(1, std::sync::atomic::Ordering::Relaxed)
181	            % self.num_streams;
182	        let pool = self
183	            .stream_pool
184	            .as_ref()
185	            .ok_or_else(|| device_error(self.device_id, "Stream pool not initialized."))?;
186	        // `DeviceFuture` implements `Drop`, so functional-update syntax
187	        // (`..Default::default()`) would move fields out of a droppable
188	        // value (E0509). Spell every field out instead.
189	        Ok(DeviceFuture {
190	            device_operation: Some(op),
191	            execution_context: Some(ExecutionContext::new(Arc::clone(&pool[idx]))),
192	            result: None,
193	            error: None,
194	            state: Default::default(),
195	            callback_state: None,
196	        })
197	    }
198	}
199	
200	/// Single-stream scheduler that serialises all work onto one CUDA stream.
201	///
202	/// Useful for debugging or when ordering guarantees are required between
203	/// all operations on a device.
204	#[derive(Debug)]
205	pub struct SingleStream {
206	    /// The single stream. `None` until [`init`](SchedulingPolicy::init).
207	    pub stream: Option<Arc<CudaStream>>,
208	}
209	
210	impl SingleStream {
211	    /// Creates an un-initialized single-stream policy.
212	    ///
213	    /// # Safety
214	    ///
215	    /// The caller must call [`SchedulingPolicy::init`] before use.
216	    pub unsafe fn new() -> Self {
217	        Self { stream: None }
