1	/*
2	 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	
6	//! Thread-local GPU device state, kernel cache, and scheduling policy management.
7	//!
8	//! Each thread maintains a set of [`AsyncDeviceContext`]s (one per device) via
9	//! the `DEVICE_CONTEXTS` thread-local. A context bundles:
10	//!
11	//! * A [`CudaContext`] for driver API calls.
12	//! * A [`GlobalSchedulingPolicy`] for stream selection.
13	//! * A dedicated deallocator stream for async `cuMemFreeAsync`.
14	//! * A kernel function cache keyed by [`FunctionKey`] hashes.
15	//!
16	//! Most users interact through the convenience functions
17	//! ([`with_default_device_policy`], [`with_cuda_context`], etc.) rather than
18	//! touching the thread-local directly.
19	//!
20	//! [`CudaContext`]: cuda_core::CudaContext
21	
22	use crate::error::{DeviceError, device_assert, device_error};
23	use crate::scheduling_policies::{GlobalSchedulingPolicy, SchedulingPolicy, StreamPoolRoundRobin};
24	use cuda_core::{CudaContext, CudaFunction, CudaModule, CudaStream};
25	use rustc_hash::FxHashMap;
26	use std::cell::Cell;
27	use std::hash::{DefaultHasher, Hash, Hasher};
28	use std::sync::Arc;
29	
30	/// Default CUDA device ordinal used when no explicit device is specified.
31	pub const DEFAULT_DEVICE_ID: usize = 0;
32	
33	/// Default number of devices initialized by `init_device_contexts_default`.
34	pub const DEFAULT_NUM_DEVICES: usize = 1;
35	
36	/// Default number of streams in the [`StreamPoolRoundRobin`] policy.
37	pub const DEFAULT_ROUND_ROBIN_STREAM_POOL_SIZE: usize = 4;
38	
39	/// Trait for types that uniquely identify a compiled kernel function.
40	///
41	/// The hash is used as the lookup key in the per-device function cache.
42	pub trait FunctionKey: Hash {
43	    /// Returns a hex-encoded hash string suitable for use as a cache key.
44	    fn get_hash_string(&self) -> String {
45	        let mut hasher = DefaultHasher::new();
46	        self.hash(&mut hasher);
47	        format!("{:x}", hasher.finish())
48	    }
49	}
50	
51	/// Cached mapping from function hash keys to loaded `(module, function)` pairs.
52	type DeviceFunctions = FxHashMap<String, (Arc<CudaModule>, Arc<CudaFunction>)>;
53	
54	/// Per-device state: CUDA context, scheduling policy, deallocator stream, and
55	/// compiled-kernel cache.
56	pub struct AsyncDeviceContext {
57	    /// Device ordinal.
58	    #[allow(dead_code)]
59	    device_id: usize,
60	    /// Primary CUDA context for this device.
61	    context: Arc<CudaContext>,
62	    /// Dedicated stream for async memory deallocation (see [`DeviceBox`]).
63	    ///
64	    /// [`DeviceBox`]: crate::device_box::DeviceBox
65	    deallocator_stream: Arc<CudaStream>,
66	    /// Scheduling policy shared (via `Arc`) with all operations on this device.
67	    policy: Arc<GlobalSchedulingPolicy>,
68	    /// Cache of loaded kernel functions, keyed by [`FunctionKey`] hashes.
69	    functions: DeviceFunctions,
70	}
71	
72	/// Container for all per-device contexts on a single thread.
73	///
74	/// Uses interior mutability ([`Cell`]) because it lives inside a
75	/// `thread_local!` and must be borrowed without `&mut`.
76	pub struct AsyncDeviceContexts {
77	    /// Currently selected default device ordinal.
78	    default_device: Cell<usize>,
79	    /// Lazily initialized map of device ordinal to context.
80	    devices: Cell<Option<FxHashMap<usize, AsyncDeviceContext>>>,
81	}
82	
83	// Thread-local storage for per-device CUDA state.
84	// Lazily initialized on first access. Each thread gets its own independent
85	// set of device contexts, streams, and kernel caches.
86	thread_local!(static DEVICE_CONTEXTS: AsyncDeviceContexts = const {
87	    AsyncDeviceContexts {
88	        default_device: Cell::new(DEFAULT_DEVICE_ID),
89	        devices: Cell::new(None),
90	    }
91	});
92	
93	/// Returns the default device ordinal for the current thread.
94	pub fn get_default_device() -> usize {
95	    DEVICE_CONTEXTS.with(|ctx| ctx.default_device.get())
96	}
97	
98	/// Initializes the thread-local device context map with capacity for
99	/// `num_devices` devices and sets `default_device_id` as the default.
100	///
101	/// Must be called at most once per thread. Returns an error if already
102	/// initialized.
103	pub fn init_device_contexts(
104	    default_device_id: usize,
105	    num_devices: usize,
106	) -> Result<(), DeviceError> {
107	    DEVICE_CONTEXTS.with(|ctx| {
108	        let devices = ctx.devices.take();
109	        let is_uninitialized = devices.is_none();
110	        ctx.devices.set(devices);
111	        device_assert(
112	            default_device_id,
113	            is_uninitialized,
114	            "Context already initialized.",
115	        )
116	    })?;
117	    let devices = FxHashMap::with_capacity_and_hasher(num_devices, Default::default());
118	    DEVICE_CONTEXTS.with(|ctx| {
119	        ctx.default_device.set(default_device_id);
120	        ctx.devices.set(Some(devices));
121	    });
122	    Ok(())
123	}
124	
125	/// Initializes the thread-local device contexts with default parameters.
126	fn init_device_contexts_default() -> Result<(), DeviceError> {
127	    let default_device = get_default_device();
128	    init_device_contexts(default_device, DEFAULT_NUM_DEVICES)
129	}
130	
131	/// Creates a new [`AsyncDeviceContext`] for `device_id` with the given policy.
132	///
133	/// Initializes the CUDA context, the scheduling policy's stream pool, and a
134	/// dedicated deallocator stream.
135	pub fn new_device_context(
136	    device_id: usize,
137	    mut policy: GlobalSchedulingPolicy,
138	) -> Result<AsyncDeviceContext, DeviceError> {
139	    let context = CudaContext::new(device_id)?;
140	    policy.init(&context)?;
141	    let deallocator_stream = context.new_stream()?;
142	    Ok(AsyncDeviceContext {
143	        device_id,
144	        context,
145	        deallocator_stream,
146	        policy: Arc::new(policy),
147	        functions: FxHashMap::default(),
148	    })
149	}
150	
151	/// Inserts a new device context into `hashmap`. Errors if the device is
152	/// already present.
153	fn init_device(
154	    hashmap: &mut FxHashMap<usize, AsyncDeviceContext>,
155	    device_id: usize,
156	    policy: GlobalSchedulingPolicy,
157	) -> Result<(), DeviceError> {
158	    let device_context = new_device_context(device_id, policy)?;
159	    let pred = hashmap.insert(device_id, device_context).is_none();
160	    device_assert(device_id, pred, "Device is already initialized.")
161	}
162	
163	/// Initializes a device with the default round-robin policy.
164	fn init_with_default_policy(
165	    hashmap: &mut FxHashMap<usize, AsyncDeviceContext>,
166	    device_id: usize,
167	) -> Result<(), DeviceError> {
168	    let policy =
169	        unsafe { StreamPoolRoundRobin::new(device_id, DEFAULT_ROUND_ROBIN_STREAM_POOL_SIZE) };
170	    init_device(
171	        hashmap,
172	        device_id,
173	        GlobalSchedulingPolicy::RoundRobin(policy),
174	    )
175	}
176	
177	/// Borrows the thread-local [`AsyncDeviceContext`] for `device_id` immutably.
178	///
179	/// Lazily initializes the context map and the specific device if needed.
180	fn with_global_device_context<F, R>(device_id: usize, f: F) -> Result<R, DeviceError>
181	where
182	    F: FnOnce(&AsyncDeviceContext) -> R,
183	{
184	    DEVICE_CONTEXTS.with(|ctx| {
185	        let mut hashmap = match ctx.devices.take() {
186	            Some(hashmap) => hashmap,
187	            None => {
188	                init_device_contexts_default()?;
189	                ctx.devices
190	                    .take()
191	                    .ok_or_else(|| device_error(device_id, "Failed to initialize context"))?
192	            }
193	        };
194	        if !hashmap.contains_key(&device_id) {
195	            init_with_default_policy(&mut hashmap, device_id)?;
196	        }
197	        let device_context = hashmap
198	            .get(&device_id)
199	            .ok_or_else(|| device_error(device_id, "Failed to get context"))?;
200	        let r = f(device_context);
201	        ctx.devices.replace(Some(hashmap));
202	        Ok(r)
203	    })
204	}
205	
206	/// Borrows the thread-local [`AsyncDeviceContext`] for `device_id` mutably.
207	///
208	/// Lazily initializes the context map and the specific device if needed.
209	fn with_global_device_context_mut<F, R>(device_id: usize, f: F) -> Result<R, DeviceError>
210	where
211	    F: FnOnce(&mut AsyncDeviceContext) -> R,
212	{
213	    DEVICE_CONTEXTS.with(|ctx| {
214	        let mut hashmap = match ctx.devices.take() {
215	            Some(hashmap) => hashmap,
216	            None => {
217	                init_device_contexts_default()?;
218	                ctx.devices
219	                    .take()
